/**
 * @public
 */
export const detect = async source => {
  let cst = null;
  try {
    cst = await lexicalAnalysis(source);
    return !cst.rootNode.isError;
  } catch {
    return false;
  } finally {
    if (cst !== null) {
      cst.delete();
    }
  }
};

